277→    private fun handleStartedEvent(it: ReaderDiscoverCommunication) {
278→        uiState.value.let { state ->
279→            if (state is DiscoverUiState.ContentUiState) {
280→                when (it.task) {
281→                    REQUEST_FIRST_PAGE -> {
282→                        _uiState.value = state.copy(reloadProgressVisibility = true)
283→                    }
284→                    REQUEST_MORE -> {
285→                        _uiState.value = state.copy(loadMoreProgressVisibility = true)
286→                    }
287→                }
288→            } else {
289→                _uiState.value = DiscoverUiState.LoadingUiState
