294→    private fun handleErrorEvent() {
295→        _uiState.value?.let { uiState ->
296→            when (uiState) {
297→                is DiscoverUiState.LoadingUiState -> {
298→                    // show fullscreen error
299→                    _uiState.value = DiscoverUiState.EmptyUiState.RequestFailedUiState { onRetryButtonClick() }
300→                }
301→                is DiscoverUiState.ContentUiState -> {
302→                    _uiState.value = uiState.copy(
303→                        reloadProgressVisibility = false,
304→                        loadMoreProgressVisibility = false
305→                    )
306→                    // show snackbar
307→                    _snackbarEvents.postValue(
308→                        Event(
309→                            SnackbarMessageHolder(
310→                                UiStringRes(R.string.reader_error_request_failed_title)
311→                            )
312→                        )
313→                    )
314→                }
315→                is DiscoverUiState.EmptyUiState.RequestFailedUiState -> Unit // Do nothing
316→                is DiscoverUiState.EmptyUiState.ShowNoFollowedTagsUiState -> Unit // Do nothing
317→                is DiscoverUiState.EmptyUiState.ShowNoPostsUiState -> Unit // Do nothing
318→            }
