483→    private fun replaceUiStateItem(before: ReaderCardUiState, after: ReaderCardUiState) {
484→        (_uiState.value as? DiscoverUiState.ContentUiState)?.let {
485→            val updatedList = it.cards.toMutableList()
486→            val index = it.cards.indexOf(before)
487→            if (index != -1) {
488→                updatedList[index] = after
489→                _uiState.value = it.copy(cards = updatedList)
490→            }
491→        }
492→    }
